using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpApiServer;

// The [McpServerToolType] attribute registers this class as a source of MCP tools.
// The SDK scans it for methods marked with [McpServerTool].
[McpServerToolType]
public class WeatherTools
{
    // Constructor-injected HttpClient — the SDK resolves this from the DI container
    // each time a tool method is invoked. The class is instantiated per-call.
    private readonly HttpClient _http;

    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    // [McpServerTool]  — exposes this method as a callable tool.
    // [Description]     — the LLM sees this text to decide when to call the tool.
    // Parameter-level [Description] tells the LLM what each argument means.
    [McpServerTool(Name = "get_weather")]
    [Description("Get the current weather for a city using the Open-Meteo API.")]
    public async Task<string> GetWeatherAsync(
        [Description("Latitude of the location (e.g. 47.6062 for Seattle)")]
        double latitude,
        [Description("Longitude of the location (e.g. -122.3321 for Seattle)")]
        double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&current=temperature_2m,wind_speed_10m";

        var response = await _http.GetFromJsonAsync<OpenMeteoResponse>(url, cancellationToken);

        if (response?.Current is null)
            return "No weather data available for the given coordinates.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool(Name = "get_forecast")]
    [Description("Get a 7-day daily temperature forecast for a location.")]
    public async Task<string> GetForecastAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min";

        var response = await _http.GetFromJsonAsync<OpenMeteoForecastResponse>(url, cancellationToken);

        if (response?.Daily is null)
            return "No forecast data available.";

        var lines = response.Daily.Time
            .Select((date, i) =>
                $"{date}: {response.Daily.TemperatureMin[i]}–{response.Daily.TemperatureMax[i]}°C")
            .ToList();

        return string.Join("\n", lines);
    }
}

// --- DTOs for the Open-Meteo JSON responses ---

public record OpenMeteoResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

public record OpenMeteoForecastResponse(
    [property: JsonPropertyName("daily")] DailyForecast? Daily);

public record DailyForecast(
    [property: JsonPropertyName("time")] List<string> Time,
    [property: JsonPropertyName("temperature_2m_max")] List<double> TemperatureMax,
    [property: JsonPropertyName("temperature_2m_min")] List<double> TemperatureMin);

